const pubData = $('loop-by-publication').item.json;
const stats = $json.items?.[0]?.statistics || {};
const views    = parseInt(stats.viewCount    || '0', 10);
const likes    = parseInt(stats.likeCount    || '0', 10);
const comments = parseInt(stats.commentCount || '0', 10);
return [{ json: {
  publicacao_id:    pubData.publicacao_id,
  plataforma:       pubData.plataforma,
  views,
  likes,
  comentarios:      comments,
  compartilhamentos: 0,
  titulo_final:     pubData.titulo_final,
  engine_usada:     pubData.engine_usada,
  nicho:            pubData.nicho,
  duracao_segundos: pubData.duracao_segundos,
  canal_id:         pubData.canal_id,
  engagement_rate:  views > 0 ? (((likes + comments) / views) * 100).toFixed(2) : '0.00',
  has_stats:        views > 0 || likes > 0,
  api_error:        false
} }];

// Substitui ai-generate-weekly-insights + build-weekly-report
// Gera insights determinísticos a partir dos dados reais
const rows = $input.all().map(i => i.json);
const tops  = rows.filter(r => r.categoria === 'top');
const flops = rows.filter(r => r.categoria === 'flop');

if (!tops.length && !flops.length) {
  return [{ json: {
    insights_json:        JSON.stringify({}),
    resumo_geral:         'Nenhum dado disponível para análise esta semana.',
    nichos_promissores:   JSON.stringify([]),
    recomendacoes:        JSON.stringify([]),
    score_semana:         0,
    report_raw:           'Sem dados'
  } }];
}

// --- Nicho com mais views no top ---
const nichoViews = {};
for (const r of tops) {
  nichoViews[r.nicho] = (nichoViews[r.nicho] || 0) + Number(r.views || 0);
}
const nichosSorted = Object.entries(nichoViews)
  .sort((a, b) => b[1] - a[1])
  .map(e => e[0]);

// --- Engine com melhor engagement médio ---
const engineEng = {};
const engineCount = {};
for (const r of tops) {
  const eng = Number(r.engagement_rate || 0);
  engineEng[r.engine_usada]   = (engineEng[r.engine_usada]   || 0) + eng;
  engineCount[r.engine_usada] = (engineCount[r.engine_usada] || 0) + 1;
}
const engineAvg = Object.entries(engineEng).map(([e, total]) => ({
  engine: e,
  avg: engineCount[e] > 0 ? (total / engineCount[e]).toFixed(2) : '0'
})).sort((a, b) => b.avg - a.avg);
const bestEngine = engineAvg[0]?.engine || 'n/a';
const bestEngineAvg = engineAvg[0]?.avg || '0';

// --- Duração que performa melhor ---
const durBuckets = { 'curto (<30s)': [], 'medio (30-60s)': [], 'longo (>60s)': [] };
for (const r of tops) {
  const dur = Number(r.duracao_segundos || 0);
  const bucket = dur < 30 ? 'curto (<30s)' : dur <= 60 ? 'medio (30-60s)' : 'longo (>60s)';
  durBuckets[bucket].push(Number(r.views || 0));
}
const durAvgs = Object.entries(durBuckets).map(([b, vs]) => ({
  bucket: b,
  avg: vs.length > 0 ? vs.reduce((a, v) => a + v, 0) / vs.length : 0
})).sort((a, b) => b.avg - a.avg);
const bestDur = durAvgs[0]?.bucket || 'n/a';

// --- Score semana: média de engagement dos tops (0-1 escala) ---
const avgEng = tops.length > 0
  ? tops.reduce((s, r) => s + Number(r.engagement_rate || 0), 0) / tops.length
  : 0;
const score_semana = Math.min(parseFloat((avgEng / 10).toFixed(2)), 1.0);

// --- Padrões de título ---
const titlePatterns = [];
const hasNumbers  = tops.filter(r => /\d/.test(r.titulo_final || '')).length;
const hasCaps     = tops.filter(r => /[A-ZÁÀÃÂÉÊÍÓÔÕÚÇ]{3,}/.test(r.titulo_final || '')).length;
const hasQuestion = tops.filter(r => /\?/.test(r.titulo_final || '')).length;
if (hasNumbers  > tops.length * 0.4) titlePatterns.push('uso de números');
if (hasCaps     > tops.length * 0.4) titlePatterns.push('letras maiúsculas');
if (hasQuestion > tops.length * 0.3) titlePatterns.push('perguntas diretas');
const tituloPattern = titlePatterns.length > 0 ? titlePatterns.join(', ') : 'variado';

// --- Recomendações ---
const recomendacoes = [];
if (nichosSorted[0]) recomendacoes.push(`Aumentar produção no nicho "${nichosSorted[0]}" (maior volume de views)`);
if (bestEngine !== 'n/a') recomendacoes.push(`Priorizar engine "${bestEngine}" (engagement médio: ${bestEngineAvg}%)`);
recomendacoes.push(`Focar em vídeos de duração ${bestDur} (melhor performance)`);
if (titlePatterns.length > 0) recomendacoes.push(`Manter padrão de títulos com: ${tituloPattern}`);
if (flops.length > 0) recomendacoes.push(`Revisar canais dos flops — ${[...new Set(flops.map(r => r.nicho))].join(', ')}`);

// --- Resumo ---
const totalViews = tops.reduce((s, r) => s + Number(r.views || 0), 0);
const resumo_geral = `Semana com ${rows.length} publicações analisadas, ${totalViews.toLocaleString('pt-BR')} views totais no top 10. Nicho destaque: ${nichosSorted[0] || 'n/a'}. Engagement médio: ${avgEng.toFixed(2)}%.`;

// --- Report legível ---
const fmt = (r) => `- "${r.titulo_final}" | nicho: ${r.nicho} | engine: ${r.engine_usada} | views: ${r.views} | eng: ${r.engagement_rate}% | dur: ${Math.round((r.duracao_segundos||0)/60)}min`;
const report_raw = `## RELATÓRIO SEMANAL\n\n### TOP 10:\n${tops.map(fmt).join('\n')}\n\n### FLOP 10:\n${flops.map(fmt).join('\n')}`;

const insightsObj = {
  resumo_geral,
  nichos_promissores: nichosSorted.slice(0, 3),
  padroes_titulo:     tituloPattern,
  padroes_duracao:    bestDur,
  engine_performance: `${bestEngine} (avg ${bestEngineAvg}%)`,
  recomendacoes,
  score_semana
};

const s = (v) => String(v || '').replace(/'/g, "''");

return [{ json: {
  insights_json:      s(JSON.stringify(insightsObj)),
  resumo_geral:       s(resumo_geral),
  nichos_promissores: s(JSON.stringify(nichosSorted.slice(0, 3))),
  recomendacoes:      s(JSON.stringify(recomendacoes)),
  score_semana,
  report_raw:         s(report_raw)
} }];

